INSERT INTO exercises (id, name_ru, name_en, description, muscle_group, secondary_muscle_groups, category, difficulty_level, duration_minutes, calories_burned, rating, instructions, equipment, technique_tip, default_reps_min, default_reps_max, created_at, updated_at) VALUES

(gen_random_uuid(), 'Жим штанги лёжа', 'Bench Press', 'Базовое упражнение для развития грудных мышц.', 'CHEST', '["SHOULDERS","TRICEPS"]', 'STRENGTH', 'INTERMEDIATE', 12, 60, 4.9, '["Лягте на скамью, стопы упираются в пол", "Снимите штангу хватом чуть шире плеч", "Опускайте штангу до касания груди, локти под углом 45", "Выжмите штангу вверх"]', '["Штанга", "Скамья для жима"]', 'Не отрывайте ягодицы от скамьи. Сохраняйте небольшой прогиб в пояснице.', 6, 12, NOW(), NOW()),

(gen_random_uuid(), 'Отжимания', 'Push-Ups', 'Классическое упражнение с весом тела для груди, плеч и трицепсов.', 'CHEST', '["SHOULDERS","TRICEPS"]', 'CALISTHENICS', 'BEGINNER', 8, 35, 4.7, '["Примите упор лёжа, руки чуть шире плеч", "Тело — прямая линия от головы до пят", "Опускайтесь до касания грудью пола", "Отожмитесь вверх, полностью выпрямляя руки"]', '[]', 'Не прогибайте поясницу и не поднимайте таз. Напрягайте пресс на протяжении всего движения.', 8, 20, NOW(), NOW()),

(gen_random_uuid(), 'Разводка гантелей лёжа', 'Dumbbell Flyes', 'Изолирующее упражнение для растяжки и сокращения грудных мышц.', 'CHEST', '["SHOULDERS"]', 'STRENGTH', 'INTERMEDIATE', 10, 40, 4.5, '["Лягте на скамью, гантели над грудью ладонями друг к другу", "Медленно разводите руки в стороны со слегка согнутыми локтями", "Опускайте до уровня плеч ощущая растяжку", "Сводите руки обратно сжимая грудь"]', '["Гантели", "Скамья"]', 'Движение напоминает объятие дерева — держите лёгкий изгиб в локтях на протяжении всего подхода.', 10, 15, NOW(), NOW()),

(gen_random_uuid(), 'Подтягивания', 'Pull-Ups', 'Базовое упражнение для развития широчайших мышц спины и бицепсов.', 'BACK', '["BICEPS","FOREARMS"]', 'CALISTHENICS', 'INTERMEDIATE', 10, 50, 4.9, '["Возьмитесь за перекладину хватом чуть шире плеч", "Из виса подтянитесь до уровня подбородка", "Медленно опуститесь в вис", "Не раскачивайтесь — работайте только мышцами"]', '["Перекладина"]', 'Сводите лопатки при подтягивании. Держите корпус прямым.', 4, 12, NOW(), NOW()),

(gen_random_uuid(), 'Тяга штанги в наклоне', 'Barbell Row', 'Мощное базовое упражнение для толщины спины. Прорабатывает широчайшие и ромбовидные.', 'BACK', '["BICEPS","SHOULDERS"]', 'STRENGTH', 'INTERMEDIATE', 12, 65, 4.8, '["Наклонитесь вперёд под углом 45 градусов спина прямая", "Возьмите штангу хватом чуть шире плеч", "Тяните штангу к животу сводя лопатки", "Медленно опустите полностью выпрямляя руки"]', '["Штанга"]', 'Не округляйте спину. Тяга идёт локтями а не руками.', 6, 12, NOW(), NOW()),

(gen_random_uuid(), 'Тяга верхнего блока', 'Lat Pulldown', 'Эффективная замена подтягиваниям для начинающих. Акцент на широчайших мышцах.', 'BACK', '["BICEPS"]', 'STRENGTH', 'BEGINNER', 10, 45, 4.6, '["Сядьте на тренажёр закрепите бёдра под валиком", "Возьмите рукоять широким хватом", "Тяните рукоять к ключицам слегка прогибаясь назад", "Медленно возвращайте вверх контролируя движение"]', '["Блочный тренажёр"]', 'Тяните локтями вниз и назад а не руками.', 8, 12, NOW(), NOW()),

(gen_random_uuid(), 'Жим гантелей стоя', 'Dumbbell Shoulder Press', 'Базовое упражнение для передних и средних пучков дельтовидных мышц.', 'SHOULDERS', '["TRICEPS"]', 'STRENGTH', 'INTERMEDIATE', 10, 50, 4.7, '["Возьмите гантели на уровне плеч ладони вперёд", "Выжмите гантели вверх до почти полного выпрямления рук", "Медленно опустите до уровня плеч", "Держите корпус прямым не прогибайтесь в пояснице"]', '["Гантели"]', 'Не наклоняйтесь назад чтобы помочь жиму. Напрягайте пресс для стабилизации.', 8, 12, NOW(), NOW()),

(gen_random_uuid(), 'Подъём гантелей через стороны', 'Lateral Raises', 'Изолирующее упражнение для средней дельты. Даёт ширину плечам.', 'SHOULDERS', '[]', 'STRENGTH', 'BEGINNER', 8, 30, 4.5, '["Стоя гантели по бокам лёгкий изгиб в локтях", "Поднимайте руки через стороны до уровня плеч", "Задержитесь на секунду в верхней точке", "Медленно опустите"]', '["Гантели"]', 'Поднимайте мизинцем вверх — это активирует среднюю дельту.', 12, 20, NOW(), NOW()),

(gen_random_uuid(), 'Сгибание рук со штангой', 'Barbell Curl', 'Классическое базовое упражнение для максимального объёма бицепса.', 'BICEPS', '["FOREARMS"]', 'STRENGTH', 'BEGINNER', 10, 35, 4.8, '["Стоя штанга хватом снизу на ширине плеч", "Сгибайте руки поднимая штангу к плечам", "Не двигайте локтями — они прижаты к туловищу", "Медленно опускайте до полного выпрямления"]', '["Штанга"]', 'Не раскачивайтесь корпусом. Контролируйте опускание — негативная фаза так же важна.', 8, 12, NOW(), NOW()),

(gen_random_uuid(), 'Молот', 'Hammer Curl', 'Упражнение для бицепса и плечевой мышцы. Нейтральный хват снижает нагрузку на запястья.', 'BICEPS', '["FOREARMS"]', 'STRENGTH', 'BEGINNER', 8, 30, 4.6, '["Стоя гантели по бокам ладонями внутрь", "Сгибайте обе руки одновременно к плечам", "Держите локти прижатыми к туловищу", "Медленно опускайте в исходное положение"]', '["Гантели"]', 'Нейтральный хват лучше прокачивает плечевую мышцу под бицепсом.', 10, 15, NOW(), NOW()),

(gen_random_uuid(), 'Отжимания на брусьях', 'Dips', 'Базовое упражнение для трицепсов нижней части груди и плеч.', 'TRICEPS', '["CHEST","SHOULDERS"]', 'CALISTHENICS', 'INTERMEDIATE', 10, 45, 4.8, '["Возьмитесь за брусья поднимите тело на прямых руках", "Медленно опускайтесь сгибая руки до 90 градусов", "Не раскачивайтесь и не наклоняйтесь вперёд", "Отжимайтесь до полного выпрямления рук"]', '["Брусья"]', 'Держите корпус вертикально для акцента на трицепс.', 6, 15, NOW(), NOW()),

(gen_random_uuid(), 'Разгибание рук на блоке', 'Cable Tricep Pushdown', 'Изолирующее упражнение для трицепса. Отлично ощущается в пиковом сокращении.', 'TRICEPS', '[]', 'STRENGTH', 'BEGINNER', 8, 30, 4.5, '["Встаньте у верхнего блока возьмите рукоять хватом сверху", "Прижмите локти к туловищу", "Разгибайте руки вниз до полного выпрямления", "Медленно возвращайте в исходное положение"]', '["Блочный тренажёр"]', 'Локти должны быть неподвижны — они работают как шарнир.', 12, 15, NOW(), NOW()),

(gen_random_uuid(), 'Планка', 'Plank', 'Статическое упражнение для развития стабильности кора и всего мышечного корсета.', 'ABS', '["FULL_BODY"]', 'CALISTHENICS', 'BEGINNER', 5, 20, 4.7, '["Примите положение упора на предплечьях", "Тело — прямая линия от головы до пят", "Напрягите пресс ягодицы и бёдра", "Удерживайте позицию 30-60 секунд"]', '["Коврик"]', 'Не опускайте таз и не поднимайте его вверх. Смотрите в пол.', NULL, NULL, NOW(), NOW()),

(gen_random_uuid(), 'Скручивания', 'Crunches', 'Базовое упражнение для верхних прямых мышц живота.', 'ABS', '[]', 'CALISTHENICS', 'BEGINNER', 8, 25, 4.3, '["Лягте на спину ноги согнуты стопы на полу", "Руки за головой или на груди", "Поднимайте плечи к коленям скручивая торс", "Медленно опускайтесь не касаясь лопатками пола"]', '["Коврик"]', 'Не тяните голову руками. Поднимайте только лопатки — поясница прижата к полу.', 15, 25, NOW(), NOW()),

(gen_random_uuid(), 'Приседания со штангой', 'Barbell Squat', 'Король всех упражнений. Комплексное движение для ног ягодиц и всего тела.', 'QUADRICEPS', '["GLUTES","HAMSTRINGS"]', 'STRENGTH', 'BEGINNER', 15, 80, 5.0, '["Штанга на верхней части трапеции ноги чуть шире плеч", "Присядьте отводя таз назад и вниз", "Колени не выходят за носки спина прямая", "Встаньте выдыхая в верхней точке"]', '["Штанга", "Стойки для приседаний"]', 'Смотрите чуть вверх. Пятки давят в пол. Колени следуют за носками.', 6, 12, NOW(), NOW()),

(gen_random_uuid(), 'Жим ногами', 'Leg Press', 'Эффективное упражнение для квадрицепсов с меньшей нагрузкой на поясницу.', 'QUADRICEPS', '["GLUTES","HAMSTRINGS"]', 'STRENGTH', 'BEGINNER', 12, 70, 4.6, '["Сядьте в тренажёр стопы на платформе чуть шире плеч", "Опустите платформу до угла 90 градусов в коленях", "Выжмите платформу до почти полного выпрямления", "Не блокируйте колени в верхней точке"]', '["Тренажёр жим ногами"]', 'Не отрывайте поясницу от сиденья. Оставляйте лёгкий изгиб в коленях.', 8, 15, NOW(), NOW()),

(gen_random_uuid(), 'Румынская тяга', 'Romanian Deadlift', 'Лучшее упражнение для бицепса бедра. Глубокая растяжка и сильное сокращение.', 'HAMSTRINGS', '["GLUTES","BACK"]', 'STRENGTH', 'INTERMEDIATE', 12, 65, 4.8, '["Стоя штанга в руках на ширине бёдер", "Наклоняйтесь вперёд отводя таз назад", "Штанга скользит по ногам вниз до середины голени", "Возвращайтесь за счёт бицепса бедра"]', '["Штанга"]', 'Держите спину прямой. Движение начинается от бёдер а не от поясницы.', 8, 12, NOW(), NOW()),

(gen_random_uuid(), 'Сгибание ног в тренажёре', 'Leg Curl', 'Изолирующее упражнение для бицепса бедра.', 'HAMSTRINGS', '[]', 'STRENGTH', 'BEGINNER', 10, 40, 4.4, '["Лягте на тренажёр лицом вниз лодыжки под валиком", "Сгибайте ноги поднимая валик к ягодицам", "Задержитесь в верхней точке на секунду", "Медленно опустите в исходное положение"]', '["Тренажёр для ног"]', 'Не поднимайте бёдра от скамьи. Движение полностью изолированное.', 10, 15, NOW(), NOW()),

(gen_random_uuid(), 'Ягодичный мостик', 'Hip Thrust', 'Лучшее упражнение для ягодиц. Максимальная активация по сравнению с другими упражнениями.', 'GLUTES', '["HAMSTRINGS"]', 'STRENGTH', 'BEGINNER', 12, 55, 4.9, '["Лягте верхней частью спины на скамью штанга на бёдрах", "Поднимайте таз вверх сжимая ягодицы", "В верхней точке бёдра параллельны полу", "Медленно опускайте таз не касаясь пола"]', '["Штанга", "Скамья", "Мат"]', 'В верхней точке сожмите ягодицы максимально и задержитесь на 1-2 секунды.', 10, 20, NOW(), NOW()),

(gen_random_uuid(), 'Выпады', 'Lunges', 'Унилатеральное упражнение для ягодиц и квадрицепсов. Развивает баланс и симметрию.', 'GLUTES', '["QUADRICEPS","HAMSTRINGS"]', 'STRENGTH', 'BEGINNER', 10, 50, 4.6, '["Стоя прямо шаг вперёд одной ногой", "Опуститесь вниз до угла 90 градусов в обоих коленях", "Заднее колено почти касается пола", "Вернитесь в исходное положение и повторите другой ногой"]', '["Гантели (опционально)"]', 'Переднее колено не выходит за носок. Корпус прямой взгляд вперёд.', 10, 16, NOW(), NOW()),

(gen_random_uuid(), 'Подъём на носки стоя', 'Standing Calf Raises', 'Основное упражнение для икроножных мышц.', 'CALVES', '[]', 'STRENGTH', 'BEGINNER', 8, 25, 4.4, '["Встаньте на край ступени или платформы", "Опуститесь на пятках максимально вниз", "Поднимитесь на носках как можно выше", "Задержитесь в верхней точке и медленно опустите"]', '["Ступень или платформа"]', 'Выполняйте медленно с полной амплитудой. Быстрые движения убирают нагрузку с мышцы.', 15, 25, NOW(), NOW()),

(gen_random_uuid(), 'Становая тяга', 'Deadlift', 'Фундаментальное упражнение задействующее более 70 процентов мышц тела.', 'FULL_BODY', '["BACK","GLUTES","HAMSTRINGS"]', 'STRENGTH', 'INTERMEDIATE', 15, 100, 5.0, '["Ноги на ширине бёдер штанга над серединой стопы", "Наклонитесь и возьмите штангу хватом чуть шире ног", "Спина прямая лопатки над грифом", "Поднимайте штангу разгибая ноги и спину одновременно"]', '["Штанга"]', 'Держите штангу близко к телу. Грудь поднята взгляд вперёд.', 4, 8, NOW(), NOW()),

(gen_random_uuid(), 'Бёрпи', 'Burpees', 'Взрывное комплексное упражнение для всего тела. Развивает силу выносливость и сжигает калории.', 'FULL_BODY', '["CHEST","QUADRICEPS","SHOULDERS"]', 'PLYOMETRIC', 'INTERMEDIATE', 10, 90, 4.7, '["Из положения стоя присядьте и упритесь руками в пол", "Прыжком примите положение планки", "Выполните отжимание", "Прыжком верните ноги к рукам и выпрыгните вверх"]', '[]', 'Держите темп но не жертвуйте техникой. При усталости замените прыжок на шаг.', 8, 15, NOW(), NOW()),

(gen_random_uuid(), 'Прыжки на скакалке', 'Jump Rope', 'Отличное кардио упражнение. Развивает координацию выносливость и сжигает калории.', 'CARDIO', '["CALVES","FULL_BODY"]', 'CARDIO', 'BEGINNER', 15, 150, 4.6, '["Возьмите скакалку за ручки встаньте в середину", "Прыгайте на носках с минимальным отрывом от пола", "Вращайте скакалку запястьями а не всей рукой", "Начните с 30 секунд и постепенно увеличивайте время"]', '["Скакалка"]', 'Приземляйтесь мягко на носки. Не смотрите на скакалку — смотрите прямо.', NULL, NULL, NOW(), NOW()),

(gen_random_uuid(), 'Приседания с прыжком', 'Jump Squats', 'Плиометрическое упражнение для развития взрывной силы ног и кардио выносливости.', 'CARDIO', '["QUADRICEPS","GLUTES"]', 'PLYOMETRIC', 'INTERMEDIATE', 10, 80, 4.5, '["Встаньте в исходное положение приседания", "Присядьте до параллели", "Взрывным движением выпрыгните максимально высоко", "Мягко приземлитесь на носки и сразу уйдите в следующий присед"]', '[]', 'Мягкое приземление ключевой момент для безопасности суставов.', 8, 15, NOW(), NOW());
